diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c0cf1a7db726..c7677ab79bf2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -654,7 +654,18 @@ Value *InstCombinerImpl::simplifyRangeCheck(ICmpInst *Cmp0, ICmpInst *Cmp1,
                                             bool Inverted) {
   // Check the lower range comparison, e.g. x >= 0
   // InstCombine already ensured that if there is a constant it's on the RHS.
-  ConstantInt *RangeStart = dyn_cast<ConstantInt>(Cmp0->getOperand(1));
+  // Check the lower range comparison, e.g. x >= 0
+  // InstCombine already ensured that if there is a constant it's on the RHS.
+  Value *RangeStartVal = Cmp0->getOperand(1);
+  const APInt *RangeStart = nullptr;
+  if (auto *CI = dyn_cast<ConstantInt>(RangeStartVal))
+    RangeStart = &CI->getValue();
+  else if (auto *CV = dyn_cast<ConstantVector>(RangeStartVal))
+    if (auto *CI = dyn_cast<ConstantInt>(CV->getSplatValue()))
+      RangeStart = &CI->getValue();
+  else if (auto *CDV = dyn_cast<ConstantDataVector>(RangeStartVal))
+    if (auto *CI = dyn_cast<ConstantInt>(CDV->getSplatValue()))
+      RangeStart = &CI->getValue();
   if (!RangeStart)
     return nullptr;

@@ -3300,7 +3311,9 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,

   // TODO: One of these directions is fine with logical and/or, the other could
   // be supported by inserting freeze.
-  if (!IsLogical) {
+  // TODO: One of these directions is fine with logical and/or, the other could
+  // be supported by inserting freeze.
+  if (!IsLogical || IsAnd) {
     // E.g. (icmp slt x, 0) | (icmp sgt x, n) --> icmp ugt x, n
     // E.g. (icmp sge x, 0) & (icmp slt x, n) --> icmp ult x, n
     if (Value *V = simplifyRangeCheck(LHS, RHS, /*Inverted=*/!IsAnd))
@@ -3311,6 +3324,8 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     if (Value *V = simplifyRangeCheck(RHS, LHS, /*Inverted=*/!IsAnd))
       return V;
   }
+      return V;
+  }

   // TODO: Add conjugated or fold, check whether it is safe for logical and/or.
   if (IsAnd && !IsLogical)
