--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3195,6 +3195,9 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
     return BinaryOperator::CreateNot(Builder.CreateSelect(A, B, Zero));

   // select (select a, true, b), true, b -> select a, true, b
+  if (match(CondVal, m_Select(m_Value(A), m_One(), m_Value(B))) &&
+      match(TrueVal, m_One()) && match(FalseVal, m_Specific(B)))
+  // select (select a, true, b), true, b -> select a, true, b
   if (match(CondVal, m_Select(m_Value(A), m_One(), m_Value(B))) &&
       match(TrueVal, m_One()) && match(FalseVal, m_Specific(B)))
     return replaceOperand(SI, 0, A);
@@ -3202,6 +3205,22 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   if (match(CondVal, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
       match(TrueVal, m_Specific(B)) && match(FalseVal, m_Zero()))
     return replaceOperand(SI, 0, A);
+  // select (select a, b, false), c, false -> select a, (b && c), false
+  // Try to combine b and c if they are icmps.
+  // select (select a, b, false), c, false -> select a, (b && c), false
+  // Try to combine b and c if they are icmps.
+  if (match(CondVal, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
+      match(FalseVal, m_Zero()) && !SelType->isVectorTy()) {
+    Value *C = TrueVal;
+    auto *ICmp1 = dyn_cast<ICmpInst>(B);
+    auto *ICmp2 = dyn_cast<ICmpInst>(C);
+    if (ICmp1 && ICmp2) {
+      if (Value *V = simplifyRangeCheck(ICmp1, ICmp2, /*Inverted=*/false))
+        return SelectInst::Create(A, V, ConstantInt::getFalse(SelType));
+      if (Value *V = simplifyRangeCheck(ICmp2, ICmp1, /*Inverted=*/false))
+        return SelectInst::Create(A, V, ConstantInt::getFalse(SelType));
+    }
+  }

   // ~(A & B) & (A | B) --> A ^ B
   if (match(&SI, m_c_LogicalAnd(m_Not(m_LogicalAnd(m_Value(A), m_Value(B))),

